func (s *GameServer) handleConnection(w http.ResponseWriter, r *http.Request) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		http.Error(w, "Authorization required", http.StatusUnauthorized)
		return
	}

	var auth AuthHeader
	if err := json.Unmarshal([]byte(authHeader), &auth); err != nil {
		http.Error(w, "Invalid auth data", http.StatusUnauthorized)
		return
	}

	if !s.validateToken(auth.Token) {
		http.Error(w, "Invalid token", http.StatusUnauthorized)
		return
	}

	role := s.parseRole(auth.Role)
	if role == RolePlayer {
		http.Error(w, "Invalid role", http.StatusUnauthorized)
		return
	}

	conn, err := net.Dial("tcp", "localhost:8081")
	if err != nil {
		http.Error(w, "Connection failed", http.StatusInternalServerError)
		return
	}

	client := &Client{
		conn:     conn,
		username: auth.Username,
		role:     role,
	}

	s.mu.Lock()
	s.clients[client] = true
	s.mu.Unlock()

	go s.handleClient(client)
}

func (s *GameServer) handleClient(client *Client) {
	defer func() {
		s.mu.Lock()
		delete(s.clients, client)
		s.mu.Unlock()
		client.conn.Close()
	}()

	scanner := bufio.NewScanner(client.conn)
	for scanner.Scan() {
		message := scanner.Text()
		s.processMessage(client, message)
	}
}

func (s *GameServer) processMessage(client *Client, message string) {
	if strings.HasPrefix(message, "/") {
		s.processCommand(client, message)
	} else {
		s.broadcastMessage(client, message)
	}
}

func (s *GameServer) processCommand(client *Client, command string) {
	parts := strings.Fields(command)
	if len(parts) == 0 {
		return
	}

	cmdName := parts[0]
	cmd, exists := s.commands[cmdName]
	if !exists {
		client.conn.Write([]byte("Unknown command\n"))
		return
	}

	if client.role < cmd.MinRole {
		client.conn.Write([]byte("Insufficient permissions\n"))
		return
	}

	if err := cmd.Handler(client, parts[1:]); err != nil {
		client.conn.Write([]byte(fmt.Sprintf("Error: %v\n", err)))
	}
}

func (s *GameServer) handleKick(client *Client, args []string) error {
	if len(args) < 1 {
		return fmt.Errorf("usage: /kick <username>")
	}

	targetUsername := args[0]
	s.mu.RLock()
	defer s.mu.RUnlock()

	for c := range s.clients {
		if c.username == targetUsername {
			c.conn.Write([]byte("You have been kicked from the server\n"))
			c.conn.Close()
			return nil
		}
	}

	return fmt.Errorf("player %s not found", targetUsername)
}

