func (s *GameServer) broadcastMessage(client *Client, message string) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	chatMsg := ChatMessage{
		Username: client.username,
		Message:  message,
	}

	data, _ := json.Marshal(chatMsg)
	
	for c := range s.clients {
		if c != client {
			c.conn.Write(append(data, '\n'))
		}
	}
}

func (s *GameServer) parseRole(roleStr string) UserRole {
	switch strings.ToLower(roleStr) {
	case "player":
		return RolePlayer
	case "moderator":
		return RoleModerator
	case "admin":
		return RoleAdmin
	case "owner":
		return RoleOwner
	default:
		return RolePlayer
	}
}

func (s *GameServer) validateToken(token string) bool {
	expectedToken := fmt.Sprintf("token_%s", s.adminKey)
	return subtle.ConstantTimeCompare([]byte(token), []byte(expectedToken)) == 1
}

